    public void handleTicker(Client client, Object message)
    {
        //
        //     {
        //         "channel": "ticker",
        //         "type": "snapshot",
        //         "data": [
        //             {
        //                 "symbol": "BTC/USD",
        //                 "bid": 108359.8,
        //                 "bid_qty": 0.01362603,
        //                 "ask": 108359.9,
        //                 "ask_qty": 17.17988863,
        //                 "last": 108359.8,
        //                 "volume": 2158.32346723,
        //                 "vwap": 108894.5,
        //                 "low": 106824,
        //                 "high": 111300,
        //                 "change": -2679.9,
        //                 "change_pct": -2.41
        //             }
        //         ]
        //     }
        //
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object ticker = Helpers.GetValue(data, 0);
        Object symbol = ((String)this.safeString(ticker, "symbol"));
        Object messageHash = this.getMessageHash("ticker", null, symbol);
        Object vwap = this.safeString(ticker, "vwap");
        Object quoteVolume = null;
        Object baseVolume = this.safeString(ticker, "volume");
        if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(baseVolume, null)) && Helpers.isTrue(!Helpers.isEqual(vwap, null))))
        {
            quoteVolume = Precise.stringMul(baseVolume, vwap);
        }
        Object last = this.safeString(ticker, "last");
        final Object finalVwap = vwap;
        final Object finalBaseVolume = baseVolume;
        final Object finalQuoteVolume = quoteVolume;
        Object result = this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", null );
            put( "datetime", null );
            put( "high", KrakenCore.this.safeString(ticker, "high") );
            put( "low", KrakenCore.this.safeString(ticker, "low") );
            put( "bid", KrakenCore.this.safeString(ticker, "bid") );
            put( "bidVolume", KrakenCore.this.safeString(ticker, "bid_qty") );
            put( "ask", KrakenCore.this.safeString(ticker, "ask") );
            put( "askVolume", KrakenCore.this.safeString(ticker, "ask_qty") );
            put( "vwap", finalVwap );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", KrakenCore.this.safeString(ticker, "change") );
            put( "percentage", KrakenCore.this.safeString(ticker, "change_pct") );
            put( "average", null );
            put( "baseVolume", finalBaseVolume );
            put( "quoteVolume", finalQuoteVolume );
            put( "info", ticker );
        }});
        Helpers.addElementToObject(this.tickers, symbol, result);
        client.resolve(result, messageHash);
    }

    public void handleTrades(Client client, Object message)
    {
        //
        //     {
        //         "channel": "trade",
        //         "type": "update",
        //         "data": [
        //             {
        //                 "symbol": "MATIC/USD",
        //                 "side": "sell",
        //                 "price": 0.5117,
        //                 "qty": 40.0,
        //                 "ord_type": "market",
        //                 "trade_id": 4665906,
        //                 "timestamp": "2023-09-25T07:49:37.708706Z"
        //             }
        //         ]
        //     }
        //
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object trade = Helpers.GetValue(data, 0);
        Object symbol = ((String)this.safeString(trade, "symbol"));
        Object messageHash = this.getMessageHash("trade", null, symbol);
        Object stored = this.safeValue(this.trades, symbol);
        if (Helpers.isTrue(Helpers.isEqual(stored, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            stored = new ArrayCache(((Number)limit).intValue());
            Helpers.addElementToObject(this.trades, symbol, stored);
        }
        Object market = this.market(symbol);
        Object parsed = this.parseTrades(data, market);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(parsed)); i++)
        {
            Helpers.callDynamically(stored, "append", new Object[]{Helpers.GetValue(parsed, i)});
        }
        client.resolve(stored, messageHash);
    }

    public void handleOHLCV(Client client, Object message)
    {
        //
        //     {
        //         "channel": "ohlc",
        //         "type": "update",
        //         "timestamp": "2023-10-04T16:26:30.524394914Z",
        //         "data": [
        //             {
        //                 "symbol": "MATIC/USD",
        //                 "open": 0.5624,
        //                 "high": 0.5628,
        //                 "low": 0.5622,
        //                 "close": 0.5627,
        //                 "trades": 12,
        //                 "volume": 30927.68066226,
        //                 "vwap": 0.5626,
        //                 "interval_begin": "2023-10-04T16:25:00.000000000Z",
        //                 "interval": 5,
        //                 "timestamp": "2023-10-04T16:30:00.000000Z"
        //             }
        //         ]
        //     }
        //
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object first = Helpers.GetValue(data, 0);
        Object marketId = this.safeString(first, "symbol");
        Object symbol = this.safeSymbol(marketId);
        if (!Helpers.isTrue((Helpers.inOp(this.ohlcvs, symbol))))
        {
            Helpers.addElementToObject(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}});
        }
        Object interval = this.safeInteger(first, "interval");
        Object timeframe = ((String)this.findTimeframe(interval));
        Object messageHash = this.getMessageHash("ohlcv", null, symbol);
        Object stored = this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
        if (Helpers.isTrue(Helpers.isEqual(stored, null)))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            stored = new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue());
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, stored);
        }
        Object ohlcvsLength = Helpers.getArrayLength(data);
        for (var i = 0; Helpers.isLessThan(i, ohlcvsLength); i++)
        {
            Object candle = Helpers.GetValue(data, Helpers.subtract(Helpers.subtract(ohlcvsLength, i), 1));
            Object datetime = this.safeString(candle, "timestamp");
            Object timestamp = this.parse8601(datetime);
            Object parsed = new java.util.ArrayList<Object>(java.util.Arrays.asList(timestamp, this.safeString(candle, "open"), this.safeString(candle, "high"), this.safeString(candle, "low"), this.safeString(candle, "close"), this.safeString(candle, "volume")));
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
        }
        client.resolve(stored, messageHash);
    }

    public Object requestId()
    {
        // their support said that reqid must be an int32, not documented
        Object reqid;
        synchronized (this) {
        reqid = this.sum(this.safeInteger(this.options, "reqid", 0), 1);
        Helpers.addElementToObject(this.options, "reqid", reqid);
        }
        return reqid;
    }

