    public void handleOrderBook(Client client, Object message)
    {
        //
        // first message (snapshot)
        //
        //     {
        //         "channel": "book",
        //         "type": "snapshot",
        //         "data": [
        //             {
        //                 "symbol": "MATIC/USD",
        //                 "bids": [
        //                     {
        //                         "price": 0.5666,
        //                         "qty": 4831.75496356
        //                     },
        //                     {
        //                         "price": 0.5665,
        //                         "qty": 6658.22734739
        //                     }
        //                 ],
        //                 "asks": [
        //                     {
        //                         "price": 0.5668,
        //                         "qty": 4410.79769741
        //                     },
        //                     {
        //                         "price": 0.5669,
        //                         "qty": 4655.40412487
        //                     }
        //                 ],
        //                 "checksum": 2439117997
        //             }
        //         ]
        //     }
        //
        // subsequent updates
        //
        //     {
        //         "channel": "book",
        //         "type": "update",
        //         "data": [
        //             {
        //                 "symbol": "MATIC/USD",
        //                 "bids": [
        //                     {
        //                         "price": 0.5657,
        //                         "qty": 1098.3947558
        //                     }
        //                 ],
        //                 "asks": [],
        //                 "checksum": 2114181697,
        //                 "timestamp": "2023-10-06T17:35:55.440295Z"
        //             }
        //         ]
        //     }
        //
        Object type = this.safeString(message, "type");
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object first = this.safeDict(data, 0, new java.util.HashMap<String, Object>() {{}});
        Object symbol = ((String)this.safeString(first, "symbol"));
        Object a = this.safeValue(first, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object b = this.safeValue(first, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object c = this.safeInteger(first, "checksum");
        Object messageHash = this.getMessageHash("orderbook", null, symbol);
        Object orderbook = null;
        if (Helpers.isTrue(Helpers.isEqual(type, "update")))
        {
            orderbook = Helpers.GetValue(this.orderbooks, symbol);
            Object storedAsks = Helpers.GetValue(orderbook, "asks");
            Object storedBids = Helpers.GetValue(orderbook, "bids");
            if (Helpers.isTrue(!Helpers.isEqual(a, null)))
            {
                this.customHandleDeltas(storedAsks, a);
            }
            if (Helpers.isTrue(!Helpers.isEqual(b, null)))
            {
                this.customHandleDeltas(storedBids, b);
            }
            Object datetime = this.safeString(first, "timestamp");
            Helpers.addElementToObject(orderbook, "symbol", symbol);
            Helpers.addElementToObject(orderbook, "timestamp", this.parse8601(datetime));
            Helpers.addElementToObject(orderbook, "datetime", datetime);
        } else
        {
            // snapshot
            Object depth = Helpers.getArrayLength(a);
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, depth));
            orderbook = Helpers.GetValue(this.orderbooks, symbol);
            Object keys = new java.util.ArrayList<Object>(java.util.Arrays.asList("asks", "bids"));
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object key = Helpers.GetValue(keys, i);
                Object bookside = Helpers.GetValue(orderbook, key);
                Object deltas = this.safeValue(first, key, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.getArrayLength(deltas), 0)))
                {
                    this.customHandleDeltas(bookside, deltas);
                }
            }
            Helpers.addElementToObject(orderbook, "symbol", symbol);
        }
        Helpers.callDynamically(orderbook, "limit", new Object[]{});
        // checksum temporarily disabled because the exchange checksum was not reliable
        Object checksum = this.handleOption("watchOrderBook", "checksum", false);
        if (Helpers.isTrue(checksum))
        {
            Object payloadArray = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            if (Helpers.isTrue(!Helpers.isEqual(c, null)))
            {
                Object checkAsks = Helpers.GetValue(orderbook, "asks");
                Object checkBids = Helpers.GetValue(orderbook, "bids");
                // const checkAsks = asks.map ((elem) => [ elem['price'], elem['qty'] ]);
                // const checkBids = bids.map ((elem) => [ elem['price'], elem['qty'] ]);
                for (var i = 0; Helpers.isLessThan(i, 10); i++)
                {
                    Object currentAsk = this.safeValue(checkAsks, i, new java.util.HashMap<String, Object>() {{}});
                    Object formattedAsk = Helpers.add(this.formatNumber(Helpers.GetValue(currentAsk, 0)), this.formatNumber(Helpers.GetValue(currentAsk, 1)));
                    ((java.util.List<Object>)payloadArray).add(formattedAsk);
                }
                for (var i = 0; Helpers.isLessThan(i, 10); i++)
                {
                    Object currentBid = this.safeValue(checkBids, i, new java.util.HashMap<String, Object>() {{}});
                    Object formattedBid = Helpers.add(this.formatNumber(Helpers.GetValue(currentBid, 0)), this.formatNumber(Helpers.GetValue(currentBid, 1)));
                    ((java.util.List<Object>)payloadArray).add(formattedBid);
                }
            }
            Object payload = String.join((String)"", (java.util.List<String>)payloadArray);
            Object localChecksum = this.crc32(payload, false);
            if (Helpers.isTrue(!Helpers.isEqual(localChecksum, c)))
            {
                var error = new ChecksumError(Helpers.add(Helpers.add(this.id, " "), this.orderbookChecksumMessage(symbol)));
                ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
                ((java.util.Map<String,Object>)this.orderbooks).remove((String)symbol);
                client.reject(error, messageHash);
                return;
            }
        }
        client.resolve(orderbook, messageHash);
    }

    public void customHandleDeltas(Object bookside, Object deltas)
    {
        // const sortOrder = (key === 'bids') ? true : false;
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(deltas)); j++)
        {
            Object delta = Helpers.GetValue(deltas, j);
            Object price = this.safeNumber(delta, "price");
            Object amount = this.safeNumber(delta, "qty");
            Helpers.callDynamically(bookside, "store", new Object[]{price, amount});
        }
    }

    public Object formatNumber(Object data)
    {
        Object parts = Helpers.split(data, ".");
        Object integer = ((String)this.safeString(parts, 0));
        Object decimals = ((String)this.safeString(parts, 1, ""));
        Object joinedResult = Helpers.add(integer, decimals);
        Object i = 0;
        while (Helpers.isEqual(Helpers.GetValue(joinedResult, i), "0"))
        {
            i = Helpers.add(i, 1);
        }
        if (Helpers.isTrue(Helpers.isGreaterThan(i, 0)))
        {
            joinedResult = Helpers.slice(joinedResult, i, null);
        }
        return joinedResult;
    }

