    public void handleMyTrades(Client client, Object message, Object... optionalArgs)
    {
        //
        //     {
        //         "channel": "executions",
        //         "type": "update",
        //         "data": [
        //             {
        //                 "order_id": "O6NTZC-K6FRH-ATWBCK",
        //                 "exec_id": "T5DIUI-5N4KO-Z5BPXK",
        //                 "exec_type": "trade",
        //                 "trade_id": 8253473,
        //                 "symbol": "USDC/USD",
        //                 "side": "sell",
        //                 "last_qty": 15.44,
        //                 "last_price": 1.0002,
        //                 "liquidity_ind": "t",
        //                 "cost": 15.443088,
        //                 "order_userref": 0,
        //                 "order_status": "filled",
        //                 "order_type": "market",
        //                 "fee_usd_equiv": 0.03088618,
        //                 "fees": [
        //                     {
        //                         "asset": "USD",
        //                         "qty": 0.3458
        //                     }
        //                 ]
        //             }
        //         ],
        //         "sequence": 10
        //     }
        //
        Object subscription = Helpers.getArg(optionalArgs, 0, null);
        Object allTrades = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object allTradesLength = Helpers.getArrayLength(allTrades);
        if (Helpers.isTrue(Helpers.isGreaterThan(allTradesLength, 0)))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.myTrades, null)))
            {
                Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
                this.myTrades = new ArrayCache(((Number)limit).intValue());
            }
            Object stored = this.myTrades;
            Object symbols = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(allTrades)); i++)
            {
                Object trade = this.safeDict(allTrades, i, new java.util.HashMap<String, Object>() {{}});
                Object parsed = this.parseWsTrade(trade);
                Helpers.callDynamically(stored, "append", new Object[]{parsed});
                Object symbol = ((String)Helpers.GetValue(parsed, "symbol"));
                Helpers.addElementToObject(symbols, symbol, true);
            }
            Object name = "myTrades";
            client.resolve(this.myTrades, name);
            Object keys = Helpers.objectKeys(symbols);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object messageHash = Helpers.add(Helpers.add(name, ":"), Helpers.GetValue(keys, i));
                client.resolve(this.myTrades, messageHash);
            }
        }
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        //     {
        //         "order_id": "O6NTZC-K6FRH-ATWBCK",
        //         "exec_id": "T5DIUI-5N4KO-Z5BPXK",
        //         "exec_type": "trade",
        //         "trade_id": 8253473,
        //         "symbol": "USDC/USD",
        //         "side": "sell",
        //         "last_qty": 15.44,
        //         "last_price": 1.0002,
        //         "liquidity_ind": "t",
        //         "cost": 15.443088,
        //         "order_userref": 0,
        //         "order_status": "filled",
        //         "order_type": "market",
        //         "fee_usd_equiv": 0.03088618,
        //         "fees": [
        //             {
        //                 "asset": "USD",
        //                 "qty": 0.3458
        //             }
        //         ]
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = this.safeString(trade, "symbol");
        if (Helpers.isTrue(!Helpers.isEqual(market, null)))
        {
            symbol = Helpers.GetValue(market, "symbol");
        }
        Object fee = null;
        if (Helpers.isTrue(Helpers.inOp(trade, "fees")))
        {
            Object fees = this.safeList(trade, "fees", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object firstFee = this.safeDict(fees, 0, new java.util.HashMap<String, Object>() {{}});
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", KrakenCore.this.safeNumber(firstFee, "qty") );
                put( "currency", KrakenCore.this.safeString(firstFee, "asset") );
            }};
        }
        Object datetime = this.safeString(trade, "timestamp");
        Object liquidityIndicator = this.safeString(trade, "liquidity_ind");
        Object takerOrMaker = ((Helpers.isTrue((Helpers.isEqual(liquidityIndicator, "t"))))) ? "taker" : "maker";
        final Object finalSymbol = symbol;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", KrakenCore.this.safeString(trade, "exec_id") );
            put( "order", KrakenCore.this.safeString(trade, "order_id") );
            put( "timestamp", KrakenCore.this.parse8601(datetime) );
            put( "datetime", datetime );
            put( "symbol", finalSymbol );
            put( "type", KrakenCore.this.safeString(trade, "order_type") );
            put( "side", KrakenCore.this.safeString(trade, "side") );
            put( "takerOrMaker", takerOrMaker );
            put( "price", KrakenCore.this.safeNumber(trade, "last_price") );
            put( "amount", KrakenCore.this.safeNumber(trade, "last_qty") );
            put( "cost", KrakenCore.this.safeNumber(trade, "cost") );
            put( "fee", finalFee );
        }};
    }

