    public void handleOrders(Client client, Object message, Object... optionalArgs)
    {
        //
        //     {
        //         "channel": "executions",
        //         "type": "update",
        //         "data": [
        //             {
        //                 "order_id": "OK4GJX-KSTLS-7DZZO5",
        //                 "order_userref": 3,
        //                 "symbol": "BTC/USD",
        //                 "order_qty": 0.005,
        //                 "cum_cost": 0.0,
        //                 "time_in_force": "GTC",
        //                 "exec_type": "pending_new",
        //                 "side": "sell",
        //                 "order_type": "limit",
        //                 "limit_price_type": "static",
        //                 "limit_price": 26500.0,
        //                 "stop_price": 0.0,
        //                 "order_status": "pending_new",
        //                 "fee_usd_equiv": 0.0,
        //                 "fee_ccy_pref": "fciq",
        //                 "timestamp": "2023-09-22T10:33:05.709950Z"
        //             }
        //         ],
        //         "sequence": 8
        //     }
        //
        Object subscription = Helpers.getArg(optionalArgs, 0, null);
        Object allOrders = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object allOrdersLength = Helpers.getArrayLength(allOrders);
        if (Helpers.isTrue(Helpers.isGreaterThan(allOrdersLength, 0)))
        {
            Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
            if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
            {
                this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            }
            Object stored = this.orders;
            Object symbols = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(allOrders)); i++)
            {
                Object order = this.safeDict(allOrders, i, new java.util.HashMap<String, Object>() {{}});
                Object id = this.safeString(order, "order_id");
                Object parsed = this.parseWsOrder(order);
                Object symbol = this.safeString(order, "symbol");
                Object previousOrders = this.safeValue(((io.github.ccxt.ws.ArrayCache)stored).hashmap, ((String)symbol));
                Object previousOrder = this.safeValue(previousOrders, ((String)id));
                Object newOrder = parsed;
                if (Helpers.isTrue(!Helpers.isEqual(previousOrder, null)))
                {
                    Object newRawOrder = this.extend(Helpers.GetValue(previousOrder, "info"), Helpers.GetValue(newOrder, "info"));
                    newOrder = this.parseWsOrder(newRawOrder);
                }
                Object length = Helpers.getArrayLength(stored);
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(length, limit)) && Helpers.isTrue((Helpers.isEqual(previousOrder, null)))))
                {
                    Object first = Helpers.GetValue(stored, 0);
                    Object symbolsByOrderId = this.safeValue(this.options, "symbolsByOrderId", new java.util.HashMap<String, Object>() {{}});
                    if (Helpers.isTrue(Helpers.inOp(symbolsByOrderId, Helpers.GetValue(first, "id"))))
                    {
                        ((java.util.Map<String,Object>)symbolsByOrderId).remove((String)Helpers.GetValue(first, "id"));
                    }
                }
                Helpers.callDynamically(stored, "append", new Object[]{newOrder});
                if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                {
                    Helpers.addElementToObject(symbols, symbol, true);
                }
            }
            Object name = "orders";
            client.resolve(this.orders, name);
            Object keys = Helpers.objectKeys(symbols);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object messageHash = Helpers.add(Helpers.add(name, ":"), Helpers.GetValue(keys, i));
                client.resolve(this.orders, messageHash);
            }
        }
    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        // watchOrders
        //
        // open order
        //     {
        //         "order_id": "OK4GJX-KSTLS-7DZZO5",
        //         "order_userref": 3,
        //         "symbol": "BTC/USD",
        //         "order_qty": 0.005,
        //         "cum_cost": 0.0,
        //         "time_in_force": "GTC",
        //         "exec_type": "pending_new",
        //         "side": "sell",
        //         "order_type": "limit",
        //         "limit_price_type": "static",
        //         "limit_price": 26500.0,
        //         "stop_price": 0.0,
        //         "order_status": "pending_new",
        //         "fee_usd_equiv": 0.0,
        //         "fee_ccy_pref": "fciq",
        //         "timestamp": "2023-09-22T10:33:05.709950Z"
        //     }
        //
        // canceled order
        //
        //     {
        //         "timestamp": "2025-10-11T15:11:47.695226Z",
        //         "order_status": "canceled",
        //         "exec_type": "canceled",
        //         "order_userref": 0,
        //         "order_id": "OGAB7Y-BKX5F-PTK5RW",
        //         "cum_qty": 0,
        //         "cum_cost": 0,
        //         "fee_usd_equiv": 0,
        //         "avg_price": 0,
        //         "cancel_reason": "User requested",
        //         "reason": "User requested"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "cost", KrakenCore.this.safeString(order, "fee_usd_equiv") );
            put( "currency", "USD" );
        }};
        Object stopPrice = this.safeString(order, "stop_price");
        Object datetime = this.safeString(order, "timestamp");
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", KrakenCore.this.safeString(order, "order_id") );
            put( "clientOrderId", KrakenCore.this.safeString(order, "order_userref") );
            put( "info", order );
            put( "timestamp", KrakenCore.this.parse8601(datetime) );
            put( "datetime", datetime );
            put( "lastTradeTimestamp", null );
            put( "status", KrakenCore.this.parseOrderStatus(KrakenCore.this.safeString(order, "order_status")) );
            put( "symbol", KrakenCore.this.safeString(order, "symbol") );
            put( "type", KrakenCore.this.safeString(order, "order_type") );
            put( "timeInForce", KrakenCore.this.safeString(order, "time_in_force") );
            put( "postOnly", null );
            put( "side", KrakenCore.this.safeString(order, "side") );
            put( "price", KrakenCore.this.safeString(order, "limit_price") );
            put( "stopPrice", stopPrice );
            put( "triggerPrice", stopPrice );
            put( "cost", KrakenCore.this.safeString(order, "cum_cost") );
            put( "amount", KrakenCore.this.safeString2(order, "order_qty", "cum_qty") );
            put( "filled", null );
            put( "average", KrakenCore.this.safeString(order, "avg_price") );
            put( "remaining", null );
            put( "fee", fee );
            put( "trades", null );
        }});
    }

    public java.util.concurrent.CompletableFuture<Object> watchMultiHelper(Object unifiedName, Object channelName, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object subscriptionArgs = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            // symbols are required
            symbols = this.marketSymbols(symbols, null, false, true, false);
            if (Helpers.isTrue(Helpers.isEqual(symbols, null)))
            {
                return null;
            }
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
            {
                Object eventTrigger = this.safeString(parameters, "event_trigger");
                if (Helpers.isTrue(!Helpers.isEqual(eventTrigger, null)))
                {
                    ((java.util.List<Object>)messageHashes).add(this.getMessageHash(channelName, null, this.symbol(Helpers.GetValue(symbols, i))));
                } else
                {
                    ((java.util.List<Object>)messageHashes).add(this.getMessageHash(unifiedName, null, this.symbol(Helpers.GetValue(symbols, i))));
                }
            }
            final Object finalSymbols = symbols;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "method", "subscribe" );
                put( "params", new java.util.HashMap<String, Object>() {{
                    put( "channel", channelName );
                    put( "symbol", finalSymbols );
                }} );
                put( "req_id", KrakenCore.this.requestId() );
            }};
            Helpers.addElementToObject(request, "params", this.deepExtend(Helpers.GetValue(request, "params"), parameters));
            Object url = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "publicV2");
            return (this.watchMultiple(url, messageHashes, request, messageHashes, subscriptionArgs)).join();
        });

    }

    /**
     * @method
     * @name kraken#watchBalance
     * @description watch balance and get the amount of funds available for trading or funds locked in orders
     * @see https://docs.kraken.com/api/docs/websocket-v2/balances
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object token = (this.authenticate()).join();
            Object messageHash = "balances";
            Object url = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "privateV2");
            Object requestId = this.requestId();
            Object subscribe = new java.util.HashMap<String, Object>() {{
                put( "method", "subscribe" );
                put( "req_id", requestId );
                put( "params", new java.util.HashMap<String, Object>() {{
                    put( "channel", "balances" );
                    put( "token", token );
                }} );
            }};
            Object request = this.deepExtend(subscribe, parameters);
            return (this.watch(url, messageHash, request, messageHash, null)).join();
        });

    }

    public void handleBalance(Client client, Object message)
    {
        //
        //     {
        //         "channel": "balances",
        //         "data": [
        //             {
        //                 "asset": "BTC",
        //                 "asset_class": "currency",
        //                 "balance": 1.2,
        //                 "wallets": [
        //                     {
        //                         "type": "spot",
        //                         "id": "main",
        //                         "balance": 1.2
        //                     }
        //                 ]
        //             }
        //         ],
        //         "type": "snapshot",
        //         "sequence": 1
        //     }
        //
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", message );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object currencyId = this.safeString(Helpers.GetValue(data, i), "asset");
            Object code = ((String)this.safeCurrencyCode(currencyId));
            Object account = this.account();
            Object eq = this.safeString(Helpers.GetValue(data, i), "balance");
            Helpers.addElementToObject(account, "total", eq);
            Helpers.addElementToObject(result, code, account);
        }
        Object type = "spot";
        Object balance = this.safeBalance(result);
        Object oldBalance = this.safeValue(this.balance, type, new java.util.HashMap<String, Object>() {{}});
        Object newBalance = this.deepExtend(oldBalance, balance);
        Helpers.addElementToObject(this.balance, type, this.safeBalance(newBalance));
        Object channel = this.safeString(message, "channel");
        client.resolve(Helpers.GetValue(this.balance, type), channel);
    }

    public Object getMessageHash(Object unifiedElementName, Object... optionalArgs)
    {
        // unifiedElementName can be : orderbook, trade, ticker, bidask ...
        // subChannelName only applies to channel that needs specific variation (i.e. depth_50, depth_100..) to be selected
        Object subChannelName = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = Helpers.getArg(optionalArgs, 1, null);
        Object withSymbol = !Helpers.isEqual(symbol, null);
        Object messageHash = unifiedElementName;
        if (!Helpers.isTrue(withSymbol))
        {
            messageHash = Helpers.add(messageHash, "s");
        } else
        {
            messageHash = Helpers.add(messageHash, Helpers.add("@", symbol));
        }
        if (Helpers.isTrue(!Helpers.isEqual(subChannelName, null)))
        {
            messageHash = Helpers.add(messageHash, Helpers.add("#", subChannelName));
        }
        return messageHash;
    }

    public void handleSubscriptionStatus(Client client, Object message)
    {
        //
        // public
        //
        //     {
        //         "channelID": 210,
        //         "channelName": "book-10",
        //         "event": "subscriptionStatus",
        //         "reqid": 1574146735269,
        //         "pair": "ETH/XBT",
        //         "status": "subscribed",
        //         "subscription": { depth: 10, name: "book" }
        //     }
        //
        // private
        //
        //     {
        //         "channelName": "openOrders",
        //         "event": "subscriptionStatus",
        //         "reqid": 1,
        //         "status": "subscribed",
        //         "subscription": { maxratecount: 125, name: "openOrders" }
        //     }
        //
        Object channelId = this.safeString(message, "channelID");
        if (Helpers.isTrue(!Helpers.isEqual(channelId, null)))
        {
            Helpers.addElementToObject(client.subscriptions, channelId, message);
        }
    }

    public Object handleErrorMessage(Client client, Object message)
    {
        //
        //     {
        //         "errorMessage": "Currency pair not in ISO 4217-A3 format foobar",
        //         "event": "subscriptionStatus",
        //         "pair": "foobar",
        //         "reqid": 1574146735269,
        //         "status": "error",
        //         "subscription": { name: "ticker" }
        //     }
        //
        // v2
        //     {
        //         "error": "Unsupported field: 'price' for the given msg type: add order",
        //         "method": "add_order",
        //         "success": false,
        //         "time_in": "2025-05-13T08:59:44.803511Z",
        //         "time_out": "2025-05-13T08:59:44.803542Z'
        //     }
        //
        Object errorMessage = this.safeString2(message, "errorMessage", "error");
        if (Helpers.isTrue(!Helpers.isEqual(errorMessage, null)))
        {
            Object requestId = this.safeString2(message, "reqid", "req_id");
            Object broad = Helpers.GetValue(Helpers.GetValue(this.exceptions, "ws"), "broad");
            Object broadKey = this.findBroadlyMatchedKey(broad, errorMessage);
            Object exception = null;
            if (Helpers.isTrue(Helpers.isEqual(broadKey, null)))
            {
                exception = new ExchangeError(                ((String)errorMessage)); // c# requirement to convert the errorMessage to string
            } else
            {
                exception = this.newException(Helpers.GetValue(broad, broadKey), errorMessage);
            }
            if (Helpers.isTrue(!Helpers.isEqual(requestId, null)))
            {
                client.reject(exception, requestId);
            }
            return false;
        }
        return true;
    }

    public void handleMessage(Client client, Object message)
    {
        Object channel = this.safeString(message, "channel");
        if (Helpers.isTrue(!Helpers.isEqual(channel, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(channel, "executions")))
            {
                Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object first = this.safeDict(data, 0, new java.util.HashMap<String, Object>() {{}});
                Object execType = this.safeString(first, "exec_type");
                channel = ((Helpers.isTrue((Helpers.isEqual(execType, "trade"))))) ? "myTrades" : "orders";
            }
            Object methods = new java.util.HashMap<String, Object>() {{
                put( "balances", "handleBalance");
                put( "book", "handleOrderBook");
                put( "ohlc", "handleOHLCV");
                put( "ticker", "handleTicker");
                put( "trade", "handleTrades");
                put( "myTrades", "handleMyTrades");
                put( "orders", "handleOrders");
            }};
            Object method = this.safeValue(methods, channel);
            if (Helpers.isTrue(!Helpers.isEqual(method, null)))
            {
                Helpers.callDynamically(this, method, new Object[] {client, message});
            }
        }
        if (Helpers.isTrue(this.handleErrorMessage(client, message)))
        {
            Object eventVar = this.safeString2(message, "event", "method");
            Object methods = new java.util.HashMap<String, Object>() {{
                put( "heartbeat", "handleHeartbeat");
                put( "systemStatus", "handleSystemStatus");
                put( "subscriptionStatus", "handleSubscriptionStatus");
                put( "add_order", "handleCreateEditOrder");
                put( "amend_order", "handleCreateEditOrder");
                put( "cancel_order", "handleCancelOrder");
                put( "cancel_all", "handleCancelAllOrders");
                put( "pong", "handlePong");
            }};
            Object method = this.safeValue(methods, ((String)eventVar));
            if (Helpers.isTrue(!Helpers.isEqual(method, null)))
            {
                Helpers.callDynamically(this, method, new Object[] {client, message});
            }
        }
    }
